mapper.select:
SELECT COUNT(*)
  FROM collaboration_friendship
 WHERE user_id = #{userId}
   AND friend_user_id = #{friendUserId}

SELECT *
  FROM collaboration_friend_request
 WHERE id = #{id}

SELECT id
  FROM collaboration_conversation
 WHERE type = 'DIRECT'
   AND user_low_id = #{userLowId}
   AND user_high_id = #{userHighId}
 LIMIT 1

SELECT *
  FROM collaboration_conversation
 WHERE id = #{id}

SELECT COUNT(*)
  FROM collaboration_conversation_invite
 WHERE conversation_id = #{conversationId}
   AND invitee_id = #{inviteeId}
   AND status = 'PENDING'

mapper.update:
UPDATE collaboration_conversation_invite
   SET status = 'ACCEPTED',
       responded_at = NOW()
 WHERE conversation_id = #{conversationId}
   AND invitee_id = #{inviteeId}
   AND status = 'PENDING'

mapper.select:
SELECT COUNT(*)
  FROM collaboration_conversation_member
 WHERE conversation_id = #{conversationId}
   AND user_id = #{userId}
   AND status = 'ACTIVE'

mapper.update:
UPDATE collaboration_conversation_member
   SET muted = #{muted}
 WHERE conversation_id = #{conversationId}
   AND user_id = #{userId}

UPDATE collaboration_conversation
   SET updated_at = NOW()
 WHERE id = #{conversationId}

UPDATE collaboration_conversation_member
   SET last_read_message_id = GREATEST(COALESCE(last_read_message_id, 0), #{messageId}),
       last_read_at = NOW()
 WHERE conversation_id = #{conversationId}
   AND user_id = #{userId}
   AND status = 'ACTIVE'
